30	int ThreadCommand::prepare(int argc, char* const argv[]) {
31	    if (!CoreApi::IsReady())
32	        return Command::FINISH;
33	
34	    if (!(argc > 1)) {
35	        LOGI("Current thread is %d\n", Env::CurrentPid());
36	        return Command::FINISH;
37	    }
38	
39	    options.native = false;
40	    options.java = false;
41	    options.dump_all = false;
42	
43	    int opt;
44	    int option_index = 0;
45	    optind = 0; // reset
46	    static struct option long_options[] = {
47	        {"native",    no_argument,       0,  'n'},
48	#if defined(__AOSP_PARSER__)
49	        {"java",      no_argument,       0,  'j'},
50	        {"all",       no_argument,       0,  'a'},
51	        {0,           0,                 0,   0 },
52	#endif
53	    };
54	
55	    while ((opt = getopt_long(argc, (char* const*)argv, "nja",
56	                long_options, &option_index)) != -1) {
57	        switch (opt) {
58	            case 'n':
59	                options.native = true;
60	                options.java = false;
61	                break;
62	            case 'j':
63	                options.native = false;
64	                options.java = true;
65	                break;
66	            case 'a':
67	                options.native = false;
68	                options.java = true;
69	                options.dump_all = true;
70	                break;
71	        }
72	    }
73	    options.optind = optind;
74	
75	#if defined(__AOSP_PARSER__)
76	    if (options.java)
77	        Android::Prepare();
78	#endif
79	
80	    return !(options.native ^ options.java) ? Command::CONTINUE : Command::ONCHLD;
81	}
82	
83	int ThreadCommand::main(int argc, char* const argv[]) {
84	    if (!(options.native ^ options.java)) {
85	        if (options.optind < argc) {
86	            int current_pid = std::atoi(argv[options.optind]);
87	            Env::SetCurrentPid(current_pid);
88	        }
89	        LOGI("Current thread is %d\n", Env::CurrentPid());
90	    } else {
91	        if (options.native) {
92	            int index = 1;
93	            int machine = CoreApi::GetMachine();
94	            LOGI(ANSI_COLOR_LIGHTRED " ID     TARGET TID        FRAME\n" ANSI_COLOR_RESET);
95	            auto callback = [&](ThreadApi *api) -> bool {
96	                uint64_t frame_pc = api->GetFramePC();
97	                File* file = CoreApi::FindFile(frame_pc);
98	                LOGI("%s%-4d   Thread " ANSI_COLOR_YELLOW "%-10d " ANSI_COLOR_CYAN "0x%" PRIx64 "  " ANSI_COLOR_GREEN "%s\n" ANSI_COLOR_RESET,
99	                        api->pid() == Env::CurrentPid() ? "*" : " ",
100	                        index, api->pid(), frame_pc, file? file->name().c_str() : "");
101	                ++index;
102	                return false;
103	            };
104	            CoreApi::ForeachThread(callback);
105	        } else {
106	#if defined(__AOSP_PARSER__)
107	            if (!Android::IsSdkReady())
108	                return 0;
109	
110	            std::vector<int> threads;
111	            auto callback = [&](ThreadApi *api) -> bool {
112	                threads.push_back(api->pid());
113	                return false;
114	            };
115	            CoreApi::ForeachThread(callback);
116	
117	            LOGI(ANSI_COLOR_LIGHTRED " ID   TID    STATUS                          ADDRESS              NAME\n" ANSI_COLOR_RESET);
118	            art::ThreadList& thread_list = art::Runtime::Current().GetThreadList();
119	            for (const auto& thread : thread_list.GetList()) {
120	                int tid = thread->GetTid();
121	                auto it = std::find(threads.begin(), threads.end(), tid);
122	                LOGI("%s%-4d " ANSI_COLOR_LIGHTYELLOW "%-6d " ANSI_COLOR_LIGHTCYAN "%-31s "
123	                               ANSI_COLOR_RESET ANSI_COLOR_LIGHTMAGENTA "0x%-16" PRIx64 "" ANSI_COLOR_RESET
124	                               "   \"" ANSI_COLOR_LIGHTRED "%s" ANSI_COLOR_RESET "\" %s\n",
125	                        tid == Env::CurrentPid() ? "*" : " ",
126	                        thread->GetThreadId(), tid, thread->GetStateDescriptor(), thread->Ptr(),
127	                        thread->GetName().c_str(), it != threads.end() ? "" : "(NOT EXIST THREAD)");
128	                if (it != threads.end()) threads.erase(it);
129	            }
130	
131	            if (options.dump_all) {
132	                for (int pid : threads) {
133	                    LOGI("%s---  " ANSI_COLOR_YELLOW "%-6d " ANSI_COLOR_CYAN "NotAttachJVM\n" ANSI_COLOR_RESET , pid == Env::CurrentPid() ? "*" : " ", pid);
134	                }
135	            }
136	#endif
137	        }
138	    }
139	
140	    return 0;
141	}
